import { describe, expect, it } from 'vitest';
import { createTestHarness, type TestHarnessAuthorResponse } from '@simodelne/pgas-server/testing.js';
import { createContentPublishingProgramEntry } from '../src/programs/content-publishing/registration.js';

describe('generated program smoke', () => {
  it('runs Content Publishing through the deterministic completion path without stub output', async () => {
    const harness = await createTestHarness(createContentPublishingProgramEntry(), {
      programName: 'content-publishing',
      defaultChannel: 'user_text',
      authorResponses: [
        effect('begin_work', { __stage_runtime: { now_iso: '2026-06-28T00:00:00.000Z', random: 0.25 } }),
        effect('complete_asset_score', { __stage_runtime: { now_iso: '2026-06-28T00:00:00.000Z', random: 0.25 } }),
        effect('complete_cms_publish', { __stage_runtime: { now_iso: '2026-06-28T00:00:00.000Z', random: 0.25 } }),
        effect('complete_editorial_review', {
          result_json: JSON.stringify({ stage: 'editorial_review', status: 'reasoned' }),
          items_json: JSON.stringify(['editorial_review-item']),
        }),
      ],
    });

    try {
      await harness.trigger('start generated smoke');
      await harness.trigger('continue generated smoke');
      await harness.trigger('continue generated smoke');
      await harness.trigger('continue generated smoke');
      const snapshot = await harness.snapshot();
      expect(snapshot.mode).toBe('complete');
      const serialized = JSON.stringify(snapshot.domain).toLowerCase();
      expect(serialized).not.toContain('stage_action_stub');
      expect(serialized).not.toContain('"todo"');
      expect(serialized).toContain('in_memory_mock');
    } finally {
      await harness.close();
    }
  });
});

function effect(name: string, payload: Record<string, unknown>): TestHarnessAuthorResponse {
  return { actions: [{ kind: 'EffectAction', name, channel: name === 'begin_work' ? 'widget_output' : 'stage_output', payload }] };
}
